module clock_gating_ff (
    input wire clk,
    input wire en,
    input wire d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin
        if (en) begin
            q <= d;
        end
        // else: do nothing, hold the previous state
    end
endmodule
